+    let queries = [
+        "SELECT * FROM products ORDER BY id",
+        "SELECT COUNT(*) FROM products",
+    ];
+
+    let mismatches = oracle_compare(&fconn, &rconn, &queries);
+    if !mismatches.is_empty() {
+        for m in &mismatches {
+            eprintln!("{m}\n");
+        }
+        panic!("{} multi-table subquery DELETE mismatches", mismatches.len());
+    }
